def build_universal_questions(state_name, regulator_title, guaranty_name,
                               ce_hours, course_label):
    """
    Returns 14 universal questions that apply to every state.
    state_name      : e.g. 'Texas'
    regulator_title : e.g. 'Commissioner of Insurance'
    guaranty_name   : e.g. 'Texas Life and Health Insurance Guaranty Association'
    ce_hours        : e.g. 24  (continuing education hours per cycle)
    course_label    : 'P&C' or 'L&H'
    """
    reg = regulator_title
    guar = guaranty_name
    st = state_name

    return [
        (f"Who is primarily responsible for regulating the insurance industry in {st}?",
         "multiple_choice", "standard",
         f"The {reg} is the chief regulator of insurance in {st}, responsible for licensing producers, approving policy forms and rates, and enforcing the state's insurance laws.",
         [(f"The {reg}", True, f"Correct. The {reg} has broad authority to regulate all aspects of insurance in {st}."),
          ("The federal Department of Insurance", False, "There is no federal Department of Insurance. Insurance regulation is primarily a state function under the McCarran-Ferguson Act."),
          ("The National Association of Insurance Commissioners (NAIC)", False, "The NAIC is a standard-setting body for regulators but has no direct regulatory authority over insurers or producers."),
          ("The state attorney general", False, "The attorney general handles legal matters but the insurance regulator has primary jurisdiction over insurance regulation.")]),

        (f"Under {st} law, which of the following is an example of misrepresentation by an insurance producer?",
         "multiple_choice", "standard",
         "Misrepresentation is an unfair trade practice that includes making false or misleading statements about the terms, benefits, or conditions of an insurance policy to induce a purchase or replacement.",
         [(f"Telling a client that a policy covers losses it does not actually cover", True, "Correct. Making false statements about policy coverage is misrepresentation — a prohibited unfair trade practice in every state."),
          ("Explaining to a client the differences between two competing policies", False, "Explaining policy differences accurately is legitimate sales practice, not misrepresentation."),
          ("Recommending a policy based on the client's stated financial needs", False, "Recommending suitable coverage based on client needs is a proper producer duty, not misrepresentation."),
          ("Delivering a policy within the time required by state law", False, "Timely policy delivery is a producer obligation, not a prohibited practice.")]),

        (f"In {st}, rebating is best defined as:",
         "multiple_choice", "standard",
         "Rebating is offering or giving any valuable consideration — cash, gifts, services, or anything of value — as an inducement to purchase insurance. It is prohibited because it undermines the integrity of filed rates and creates unfair competitive advantages.",
         [("Offering anything of value as an inducement to purchase insurance", True, "Correct. Rebating is giving or promising any valuable consideration beyond the policy itself to induce an insurance purchase."),
          ("Charging a client more than the filed premium rate", False, "Charging above filed rates is overcharging, not rebating. Rebating involves giving value back, not charging more."),
          ("Replacing one policy with another without the client's consent", False, "Replacing a policy without consent is twisting (when misrepresentation is involved), not rebating."),
          ("Splitting a commission with another licensed producer", False, "Commission sharing between licensed producers is generally permitted; rebating involves giving value to the client as an inducement.")]),

        (f"An insurance producer in {st} who uses misrepresentation to persuade a policyholder to cancel an existing policy and purchase a new one is guilty of:",
         "multiple_choice", "standard",
         "Twisting is the use of misrepresentation or incomplete comparison of policies to induce a policyholder to lapse, forfeit, or surrender an existing policy and take out a new one. It is a prohibited unfair trade practice in all states.",
         [("Twisting", True, "Correct. Using misrepresentation to induce a policyholder to replace an existing policy is twisting — a prohibited unfair trade practice."),
          ("Rebating", False, "Rebating involves giving something of value as an inducement to purchase, not using misrepresentation to replace an existing policy."),
          ("Defamation", False, "Defamation involves making false statements about another insurer or producer, not inducing policy replacement through misrepresentation."),
          ("Churning", False, "Churning is replacement within the same company primarily for commission; twisting involves misrepresentation across companies.")]),

        (f"Under {st} insurance law, a producer's license may be suspended or revoked for which of the following reasons?",
         "multiple_choice", "standard",
         "Insurance licenses may be suspended or revoked for a wide range of misconduct including misappropriation of premiums, misrepresentation, fraud, and other violations of the insurance code. Failing a single exam is not grounds for license action.",
         [("Misappropriating client premium funds", True, "Correct. Misappropriating client premiums is a serious violation of fiduciary duty and is grounds for license suspension or revocation in every state."),
          ("Failing the licensing exam on the first attempt", False, "Failing an exam is not grounds for license discipline. Candidates may retake the exam."),
          ("Selling only one type of insurance product", False, "Specializing in one type of insurance is not a violation; producers can hold limited lines licenses."),
          ("Recommending a competitor's product to a client", False, "Recommending a competitor's product, while unusual, is not a prohibited act or grounds for license action.")]),

        (f"In {st}, when a licensed producer collects a premium payment from a client, those funds are considered:",
         "multiple_choice", "standard",
         "Premium funds collected by a producer belong to the insurer and must be held in a fiduciary capacity. The producer may not commingle them with personal or business operating funds. Misappropriation of premium funds is both a licensing violation and a crime.",
         [("Fiduciary funds that must be held separately from the producer's own money", True, "Correct. Collected premiums are fiduciary funds — the producer is a temporary custodian and must not commingle them with personal funds."),
          ("The producer's personal income until transmitted to the insurer", False, "Premium funds are never the producer's personal income. They must be held separately and transmitted to the insurer."),
          ("Subject to a producer's lien until earned commissions are deducted", False, "Producers cannot retain premiums as a lien for commissions. Premiums must be transmitted in full."),
          ("Unclaimed until the policy is formally issued", False, "Premium funds must be held as fiduciary property from the moment they are collected, regardless of policy issuance status.")]),

        (f"The purpose of {st}'s insurance guaranty association is to:",
         "multiple_choice", "standard",
         f"The {guar} protects policyholders when a licensed insurer becomes insolvent. It pays covered claims up to specified limits so that policyholders do not lose benefits due to insurer insolvency. It is funded by assessments on licensed insurers.",
         [(f"Pay covered claims when a licensed insurer becomes insolvent", True, f"Correct. The {guar} protects policyholders by paying covered claims when a licensed insurer is declared insolvent."),
          ("Regulate insurance rates to keep premiums affordable", False, "Rate regulation is the function of the state insurance regulator, not the guaranty association."),
          ("Provide reinsurance to small insurance companies", False, "Reinsurance is a private market function; the guaranty association does not provide reinsurance."),
          ("Manage the state's high-risk insurance pool", False, "High-risk pools (FAIR plans, assigned risk plans) are separate mechanisms; the guaranty association specifically handles insolvency claims.")]),

        (f"Under {st} law, when a producer wants to replace a client's existing life insurance policy with a new one, the producer must:",
         "multiple_choice", "standard",
         "Replacement regulations require producers to provide written comparison documents to clients and notify the existing insurer, protecting consumers from being disadvantaged by uninformed replacement decisions.",
         [("Provide a written comparison disclosure and notify the existing insurer", True, "Correct. Replacement regulations in every state require comparison disclosures to the client and notification to the insurer whose policy is being replaced."),
          ("Obtain written approval from the state insurance department", False, "State approval is not required for individual replacements. The requirements are disclosure and notification."),
          ("Cancel the existing policy before placing the new policy", False, "The replacement should be in place before the existing policy is cancelled to avoid a coverage gap."),
          ("Charge no commission on the replacement policy", False, "Commission restrictions are not a standard replacement regulation requirement.")]),

        (f"In {st}, a nonresident producer who is licensed in another state wants to obtain a {st} license. Generally, this producer:",
         "multiple_choice", "standard",
         "Most states participate in nonresident licensing reciprocity — if a producer is licensed in good standing in their home state, the nonresident state will issue a license without requiring a separate exam, as long as the home state offers the same reciprocity.",
         [("May be issued a nonresident license without taking the state exam if their home state offers reciprocity", True, "Correct. Most states grant nonresident licenses by reciprocity to producers in good standing in their home state without requiring a separate examination."),
          ("Must take and pass the full state licensing exam regardless of home state license", False, "Most states waive the exam requirement for nonresident applicants whose home state has a reciprocal licensing agreement."),
          ("Must establish a business office in the state before receiving a license", False, "Nonresident producers are not required to maintain a physical office in the state where they hold a nonresident license."),
          ("Is exempt from all continuing education requirements in the nonresident state", False, "Nonresident producers may be subject to continuing education requirements, though many states accept home state CE compliance.")]),

        (f"In {st}, which of the following activities constitutes coercion in the sale of insurance?",
         "multiple_choice", "standard",
         "Coercion is using threats, force, or economic pressure to compel someone to purchase insurance or do business with a particular insurer or producer. It is a prohibited unfair trade practice in all states.",
         [("Threatening to cancel a client's business contract unless they purchase insurance through you", True, "Correct. Using threats or economic pressure to compel an insurance purchase is coercion — a prohibited unfair trade practice."),
          ("Recommending a specific insurer based on financial strength ratings", False, "Recommending an insurer based on objective financial criteria is legitimate sales practice, not coercion."),
          ("Explaining the penalties for driving without required auto insurance", False, "Explaining legal requirements is not coercion; it is informing the client of their legal obligations."),
          ("Offering a client a choice between two different policy options", False, "Offering policy choices is standard sales practice, not coercion.")]),

        (f"A {st} insurance producer's license must be renewed every:",
         "multiple_choice", "standard",
         f"{st} requires producers to renew their license on a regular cycle and complete continuing education as a condition of renewal. Most states use a 2-year renewal cycle with required CE hours.",
         [("Two years, with continuing education requirements", True, f"Correct. Most states including {st} require license renewal every two years with completion of required continuing education hours."),
          ("One year, without any continuing education requirement", False, "Annual renewal without CE is not the standard; most states use 2-year cycles with CE requirements."),
          ("Five years, with no exam required at renewal", False, "5-year renewal cycles are not standard. Most states use 2-year cycles."),
          ("There is no renewal requirement once a license is issued", False, "All state insurance licenses require periodic renewal and continuing education.")]),

        (f"Under {st} law, a temporary insurance license may be issued to:",
         "multiple_choice", "standard",
         "Temporary licenses are designed for specific limited circumstances — most commonly to allow a surviving family member or business partner to continue operating an insurance agency when the licensed owner dies or becomes disabled.",
         [("A surviving spouse or family member to continue an agency after the death of a licensed producer", True, "Correct. Temporary licenses are most commonly issued to allow continuity of an agency after the death or incapacitation of the licensed producer."),
          ("Any person who applies for a license while waiting for exam results", False, "Waiting for exam results does not qualify a person for a temporary license. Temporary licenses are for specific qualifying circumstances."),
          ("A person who failed the licensing exam and needs time to retake it", False, "Exam failure does not qualify a person for a temporary license."),
          ("Any unlicensed employee of an insurance agency", False, "Simply being employed by an agency does not qualify someone for a temporary license.")]),

        (f"In {st}, which of the following best describes an agent's express authority?",
         "multiple_choice", "standard",
         "Express authority is explicitly granted in writing through the agency agreement between the producer and the insurer. It is the most clearly defined type of authority and specifically states what the producer may and may not do.",
         [("Authority that is specifically granted in the written agency agreement", True, "Correct. Express authority is explicitly stated in the written contract between the producer and the insurer."),
          ("Authority that arises from the producer's position and normal business customs", False, "Authority arising from position and custom is implied authority, not express authority."),
          ("Authority created when a third party reasonably believes the producer has authority based on the insurer's conduct", False, "Authority created by the insurer's conduct creating a reasonable belief is apparent authority, not express authority."),
          ("Authority that the producer assumes without any written agreement", False, "Assumed authority without written authorization is not recognized as a valid type of authority.")]),

        (f"Under {st} insurance law, defamation by an insurance producer is best defined as:",
         "multiple_choice", "standard",
         "Defamation is making false statements about another insurer, producer, or the insurance business that injure that party's reputation. Truth is a complete defense to defamation — only false statements constitute this unfair trade practice.",
         [("Making false statements that injure the reputation of another insurer or producer", True, "Correct. Defamation is making false statements about another insurer or producer. Truthful statements, even if damaging, are not defamation."),
          ("Accurately reporting a competitor's financial difficulties to a client", False, "Truthful statements are not defamation, even if they harm a competitor's reputation."),
          ("Failing to disclose a material fact about a policy to a client", False, "Failure to disclose is misrepresentation by omission, not defamation. Defamation involves false statements about others."),
          ("Using intimidation to prevent a client from shopping other insurers", False, "Using intimidation to prevent competition is coercion, not defamation.")]),
    ]


def build_semi_universal(state_name, regulator_title, guaranty_name,
                          ce_hours, course_label, license_fee_note=""):
    """6 questions with slightly state-specific facts."""
    st = state_name
    reg = regulator_title

    return [
        (f"A {st} insurance producer who moves to a new address must notify the {reg} within:",
         "multiple_choice", "standard",
         "Producers are required to keep their address current with the state insurance regulator. Most states require notification within 30 days of an address change. Failure to notify is a licensing violation.",
         [("30 days of the address change", True, f"Correct. Most states require producers to notify the {reg} of address changes within 30 days."),
          ("5 business days of the address change", False, "5 business days is shorter than the standard requirement. Most states allow 30 days."),
          ("60 days of the address change", False, "60 days exceeds the typical requirement. Most states require notification within 30 days."),
          ("At the next license renewal", False, "Address changes must be reported promptly — not deferred until renewal.")]),

        (f"In {st}, continuing education requirements for licensed insurance producers typically include:",
         "multiple_choice", "standard",
         "Most states require producers to complete continuing education hours each renewal cycle, with a portion dedicated specifically to ethics. The exact hours vary by state but the requirement to include ethics is nearly universal.",
         [(f"A specified number of hours including an ethics component", True, "Correct. Most states require a minimum number of CE hours per renewal cycle, including a required ethics component."),
          ("Only product knowledge courses with no ethics requirement", False, "Ethics is a required component of CE in virtually all states, not optional."),
          ("CE is optional — only required if the producer had a complaint filed", False, "CE is a mandatory renewal requirement for all producers, not triggered by complaints."),
          ("A state exam retake every renewal cycle", False, "Retaking the exam is not a CE requirement. CE involves approved courses, not re-examination.")]),

        (f"Under {st} law, an insurance producer who is convicted of a felony must:",
         "multiple_choice", "standard",
         "Most state insurance laws and federal law (18 USC 1033) require producers to report criminal convictions to the state insurance regulator. Failure to report is itself a violation and can result in license action.",
         [("Report the conviction to the state insurance regulator within the required timeframe", True, "Correct. Most states require producers to report felony convictions to the regulator, typically within 30 days."),
          ("Immediately surrender their license without any hearing", False, "A conviction triggers a reporting requirement and may lead to a hearing, but automatic immediate surrender without process is not the standard procedure."),
          ("Only report the conviction if it relates to financial crimes", False, "Most states require reporting of all felony convictions, not just financially related ones."),
          ("Wait until the conviction is final before reporting", False, "Most states require reporting upon conviction, not upon completion of all appeals.")]),

        (f"In {st}, which entity must give prior approval before an insurance producer can use advertising materials?",
         "multiple_choice", "standard",
         "Insurance advertising is regulated primarily by the insurer, not the state regulator on a pre-approval basis for most lines. The insurer is responsible for ensuring its advertising complies with state law. Some states require filing of advertising materials.",
         [("The insurer the producer represents", True, "Correct. The insurer must review and approve advertising materials used by its producers to ensure compliance with state advertising regulations."),
          ("The state insurance department must pre-approve all advertisements", False, "While some states require filing of advertisements, pre-approval by the state department is not required for most lines."),
          ("A national advertising standards board", False, "There is no national advertising standards board for insurance."),
          ("No approval is needed — producers may advertise freely", False, "Insurance advertising is regulated and must comply with state law; insurer approval is typically required.")]),

        (f"The {guaranty_name} covers claims when:",
         "multiple_choice", "standard",
         f"The guaranty association protects policyholders when a licensed insurer becomes insolvent. Coverage is subject to per-claim and per-policyholder limits that vary by state. The guaranty association does not cover claims against unlicensed (non-admitted) insurers.",
         [(f"A licensed admitted insurer is declared insolvent", True, f"Correct. The guaranty association covers claims when a licensed (admitted) insurer becomes insolvent — not when unlicensed insurers fail."),
          ("A claim is denied by any insurer for any reason", False, "The guaranty association only covers insolvency situations, not ordinary claim denials."),
          ("A policyholder cannot afford to pay their premium", False, "Premium affordability is not a triggering condition for guaranty association coverage."),
          ("An unauthorized (non-admitted) insurer fails to pay claims", False, "The guaranty association covers failures of licensed admitted insurers only. Non-admitted insurer failures are not covered.")]),

        (f"Under {st} law, a producer who shares a commission with an unlicensed person:",
         "multiple_choice", "standard",
         "Sharing commissions with unlicensed individuals is a prohibited practice in all states. Commissions may only be shared with licensed producers. Violations can result in license suspension or revocation.",
         [("Violates state insurance law and may have their license suspended or revoked", True, "Correct. Sharing commissions with unlicensed persons is prohibited and is grounds for license discipline."),
          ("Is permitted as long as the unlicensed person performed legitimate services", False, "Performing legitimate services does not authorize commission sharing with an unlicensed person."),
          ("Must report the sharing arrangement to the state insurance department", False, "The sharing arrangement itself is prohibited; there is no disclosure option that makes it permissible."),
          ("Is only permitted if the unlicensed person is a family member", False, "Family relationships do not create an exception to the prohibition on commission sharing with unlicensed persons.")]),
    ]


