COURSES = [("pc", "P&C"), ("lh", "L&H")]


def seed():
    create_all()
    db = SessionLocal()
    try:
        total_mods = total_q = 0

        for (abbr, name, regulator, guaranty, ce_hours) in STATES_PART1:
            for (course_code, course_label) in COURSES:
                mod_slug = f"state-law-{abbr.lower()}-{course_code}"

                existing = db.scalar(
                    select(Module).where(Module.slug == mod_slug))
                if existing:
                    print(f"  SKIP (exists): {mod_slug}")
                    continue

                mod = Module(
                    slug=mod_slug,
                    title=f"{name} State Law — {course_label}",
                    description=(
                        f"State-specific insurance laws and regulations for the "
                        f"{name} {course_label} licensing exam. Covers the "
                        f"{regulator}, licensing requirements, unfair trade "
                        f"practices, guaranty association, and state-specific rules."
                    ),
                    sort_order=500 + STATES_PART1.index(
                        (abbr, name, regulator, guaranty, ce_hours)) * 10 +
                               (0 if course_code == "pc" else 1),
                    is_active=True,
                )
                db.add(mod)
                db.flush()
                db.execute(
                    text("UPDATE modules SET course=:c WHERE id=:id"),
                    {"c": course_code, "id": mod.id})
                total_mods += 1
                print(f"  MODULE: {mod.title}")

                all_questions = (
                    build_universal_questions(
                        name, regulator, guaranty, ce_hours, course_label) +
                    build_semi_universal(
                        name, regulator, guaranty, ce_hours, course_label) +
                    build_state_specific(abbr)
                )

                for (q_text, q_type, difficulty,
                     explanation, choices) in all_questions:
                    q = Question(
                        module_id=mod.id,
                        lesson_id=None,
                        question_text=q_text,
                        question_type=q_type,
                        difficulty=difficulty,
                        explanation=explanation,
                        is_active=True,
                    )
                    db.add(q)
                    db.flush()
                    for sort_i, (ct, correct, ce) in enumerate(choices, 1):
                        db.add(AnswerChoice(
                            question_id=q.id,
                            choice_text=ct,
                            is_correct=correct,
                            explanation=ce,
                            sort_order=sort_i,
                        ))
                    total_q += 1

        db.commit()
        print(f"\n=== Part 1 complete: {total_mods} modules, "
              f"{total_q} questions ===")
        print(f"States covered: AL AK AZ AR CA CO CT DE DC FL GA HI IL")
        print(f"Courses: P&C and L&H for each state")

    finally:
        db.close()


if __name__ == "__main__":
    seed()
